SELECT symbol
FROM parameters
WHERE default_value = (SELECT MAX(default_value) FROM parameters);

SELECT product_name
FROM products
ORDER BY product_name;

SELECT MIN(min_value) AS lowest_min_value
FROM parameter_limits
WHERE product_param_id = 1;

SELECT min_value, max_value
FROM parameter_limits
WHERE revision = 'Rev1' AND product_param_id = 1;

SELECT product_name
FROM products
ORDER BY product_name;

SELECT min_value, max_value
  FROM product_parameters
  WHERE product_id = 1;

SELECT process_name, description
FROM manufacturing_processes
WHERE process_id = 1;
